// Phase 1: Image Ingest
const images = await claudeCode.uploadImages();
const imageData = images.map(img => ({
  id: `img_${img.filename.slice(0,20)}`.replace(/[^a-z0-9]/g,'-'),
  base64: img.base64,
  filename: img.filename
}));

// Phase 2: Parallel processing
const results = await Promise.all(imageData.map(async (img) => {
  const tokens = await claudeCode.prompt({
    image: img.base64,
    prompt: `Extract primitive + semantic tokens using scheme:
color.background.primary → #F9FAFB
space.card.padding → 16px
accessibility.contrast.primary-text-on-surface → 4.8:1`
  });
  return { ...img, tokens: JSON.parse(tokens) };
}));

// Phase 3: Assemble outputs
await claudeCode.generateFiles({
  'ui-style-guide.md': generateStyleGuide(results),
  'ui-components.md': generateComponents(results),
  'screen-reference.md': generateScreenRef(results),
  'accessibility-tokens.md': generateAccessibility(results),
  'progress-tracker.md': generateProgressTable(results)
});

console.log('✅ Generated 5 design system files');

export function generateStyleGuide(results: any[]) {
  const tokens = aggregateTokens(results);
  return `
## Color System (Semantic)
${Object.entries(tokens.colors.semantic).map(([k,v]) => `**${k}** → ${v}`).join('\n')}

## Spacing System
${Object.entries(tokens.spacing).map(([k,v]) => `**${k}** → ${v}px`).join('\n')}

## Accessibility Tokens
**accessibility.contrast.primary-text-on-surface** → 4.8:1 ✅`;
}

export function aggregateTokens(results: any[]) {
  // Merge + dedupe tokens across images
  return {
    colors: { semantic: {}, primitive: {} },
    spacing: {},
    radius: {},
    typography: {}
  };
}
